    prefixSum := int64(0)
    modMap := make(map[int64]int)
    modMap[0] = -1
    var segments [][]int

    for i, num := range nums {
        prefixSum += num
        mod := prefixSum % k
        if pos, exists := modMap[mod]; exists {
            segments = append(segments, []int{pos + 1, i})
        }
        modMap[mod] = i
    }

    if len(segments) == 0 {
        var sum int64
        for _, num := range nums {
            sum += num
        }
        return sum
    }

    // Sort segments by start index
    sort.Slice(segments, func(i, j int) bool {
        return segments[i][0] < segments[j][0]
    })

    // Merge overlapping or adjacent segments
    merged := [][]int{segments[0]}
    for i := 1; i < len(segments); i++ {
        last := merged[len(merged)-1]
        current := segments[i]
        if current[0] > last[1] {
            merged = append(merged, current)
        } else {
            newEnd := current[1]
            if last[1] > newEnd {
                newEnd = last[1]
            }
            merged[len(merged)-1] = []int{last[0], newEnd}
        }
    }

    // Calculate total removed sum
    totalRemoved := int64(0)
    for _, seg := range merged {
        start, end := seg[0], seg[1]
        for i := start; i <= end; i++ {
            totalRemoved += nums[i]
        }
    }

    // Calculate total sum
    totalSum := int64(0)
    for _, num := range nums {
        totalSum += num
    }

    return totalSum - totalRemoved
}
