        mod = prefix_sum % k
        if mod in mod_map:
            segments.append((mod_map[mod] + 1, i))
        mod_map[mod] = i

    segments.sort()
    merged = []
    for start, end in segments:
        if not merged:
            merged.append((start, end))
        else:
            last_start, last_end = merged[-1]
            if start > last_end:
                merged.append((start, end))
            else:
                new_end = max(end, last_end)
                merged[-1] = (last_start, new_end)

    total_removed = 0
    for start, end in merged:
        total_removed += sum(nums[start:end+1])

    return sum(nums) - total_removed
